@Entity
data class ForecastRecord(
    @PrimaryKey val id: Int,
    val city: String,
    val date: String,
    val highTemp: Int
)

@Dao
interface ForecastDao {
    @Query("SELECT * FROM ForecastRecord WHERE city = :cityName")
    suspend fun getForecastsForCity(cityName: String): List<ForecastRecord>
}

@Dao
interface ForecastDao {
    @Query("SELECT * FROM ForecastRecord")
    fun observeAllForecasts(): Flow<List<ForecastRecord>>
}

